<?php $adminTitle='LMS Enrollments'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ enroll_learner($pdo,(int)$_POST['learner_id'],(int)$_POST['course_id']); header('Location: lms-enrollments.php'); exit; } $learners=$pdo->query('SELECT * FROM learners ORDER BY full_name')->fetchAll(); $courses=get_courses($pdo,false); $rows=$pdo->query('SELECT e.*,l.full_name,c.title FROM lms_enrollments e JOIN learners l ON l.id=e.learner_id JOIN lms_courses c ON c.id=e.course_id ORDER BY e.enrolled_at DESC')->fetchAll(); ?><h1>Enrollments</h1><form class="glass-card mb-4" method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><div class="row g-3"><div class="col-md-5"><select class="form-select" name="learner_id"><?php foreach($learners as $l): ?><option value="<?= (int)$l['id']; ?>"><?= e($l['full_name'].' - '.$l['email']); ?></option><?php endforeach; ?></select></div><div class="col-md-5"><select class="form-select" name="course_id"><?php foreach($courses as $c): ?><option value="<?= (int)$c['id']; ?>"><?= e($c['title']); ?></option><?php endforeach; ?></select></div><div class="col-md-2"><button class="btn btn-premium w-100">Enroll</button></div></div></form><div class="glass-card"><table class="table table-dark"><tr><th>Learner</th><th>Course</th><th>Status</th><th>Date</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['full_name']); ?></td><td><?= e($r['title']); ?></td><td><?= e($r['status']); ?></td><td><?= e($r['enrolled_at']); ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__.'/../includes/admin-footer.php'; ?>